.mzk-side-rail{width:100%;display:flex;flex-direction:column;align-items:stretch;justify-content:flex-start;gap:12px}.mzk-controls{width:100%;display:flex;flex-direction:column;gap:8px;padding:10px;border-radius:22px;background:#fff;border:1px solid #EDE9FA;box-shadow:0 8px 24px rgba(127,119,221,.08);text-align:center;box-sizing:border-box}.mzk-btn{width:100%;padding:12px 14px;border:none;border-radius:12px;background:var(--mz-purple);color:#fff;cursor:pointer;font-weight:900;font-family:'Nunito',sans-serif;font-size:13px;box-shadow:0 6px 18px rgba(127,119,221,.18)}.mzk-btn.secondary{background:#F97316}.mzk-btn.next{background:#7F77DD}.mzk-side-hint{color:#8B83C8;font-size:12px;font-weight:900;line-height:1.18;text-align:center;padding:0 8px}.mzk-node{cursor:pointer}.mzk-node-circle{fill:#fff;stroke:none}.mzk-node.done .mzk-node-circle{stroke:var(--mz-green);stroke-width:4;fill:var(--mz-green-soft)}.mzk-node.wrong .mzk-node-circle{stroke:var(--mz-red);stroke-width:4;fill:var(--mz-red-soft)}.mzk-node image{pointer-events:none}.mzk-node.shake{animation:mzkShake .4s}@keyframes mzkShake{10%,90%{transform:translateX(-2px)}20%,80%{transform:translateX(3px)}30%,50%,70%{transform:translateX(-5px)}40%,60%{transform:translateX(5px)}}
