<script src="maze_layout.js"></script><script>
const MZK_TITLE=<?php echo json_encode($viewerTitle, JSON_UNESCAPED_UNICODE); ?>,MZK_ACTIVITY_ID=<?php echo json_encode($activityId, JSON_UNESCAPED_UNICODE); ?>,MZK_RETURN_TO=<?php echo json_encode($returnTo, JSON_UNESCAPED_UNICODE); ?>,MZK_BANK_BY_ID=<?php echo json_encode($bankById, JSON_UNESCAPED_UNICODE); ?>,MZK_PATH=<?php echo json_encode($activity['path_sequence'], JSON_UNESCAPED_UNICODE); ?>,MZK_BRANCHES=<?php echo json_encode($activity['distractor_branches'], JSON_UNESCAPED_UNICODE); ?>,MZK_LAYOUT_POSITIONS=<?php echo json_encode((object)$activity['layout_positions'], JSON_UNESCAPED_UNICODE); ?>,MZK_AUDIO_URLS=<?php echo json_encode($activity['audio_urls'], JSON_UNESCAPED_UNICODE); ?>,MZK_THEME=<?php echo json_encode($activity['theme'], JSON_UNESCAPED_UNICODE); ?>,MZK_TTS_URL='tts.php';
let mzkNextIndex=0,mzkDone=false,mzkScores=[],mzkLastLayout=null,mzkRounds=0;
function mzkPlay(el){try{if(!el)return;el.pause();el.currentTime=0;el.play();}catch(e){}}
function mzkNodeVocab(node){return MZK_BANK_BY_ID[node.vocabularyId]||{image_url:'',word:''};}
function mzkSetFeedback(text,cls){const el=document.getElementById('mzkFeedback');el.textContent=text;el.className=cls||'';}
function mzkUpdateProgress(value){if(typeof value==='number')mzkNextIndex=value;const total=Math.max(1,MZK_PATH.length),pct=Math.round(mzkNextIndex/total*100);document.getElementById('mzkFill').style.width=Math.max(pct,0)+'%';document.getElementById('mzkBadge').textContent=mzkNextIndex+' / '+MZK_PATH.length;}
function mzkSyncArrowProgress(value){mzkNextIndex=Math.max(0,Math.min(MZK_PATH.length,value||0));mzkScores=Array(mzkNextIndex).fill(1);mzkUpdateProgress();}
function mzkClearAnswerPath(){const svg=document.querySelector('#mzkMazeWrap svg');if(!svg)return;svg.querySelectorAll('.mzk-answer-path,.mzk-answer-dot').forEach(el=>el.remove());}
function mzkRenderMazeBaseSafe(NS,svg,layout){mzkRenderMazeBase(NS,svg,layout,{wallColor:'var(--wall)',floorColor:'#ffffff',dotColor:'rgba(83,74,183,.10)'});}
function mzkBuildMaze(){const layout=generateMazeLayout(MZK_PATH,MZK_BRANCHES,MZK_LAYOUT_POSITIONS);mzkLastLayout=layout;const NS='http://www.w3.org/2000/svg';const svg=document.createElementNS(NS,'svg');svg.setAttribute('viewBox','0 0 '+layout.width+' '+layout.height);svg.setAttribute('width',layout.width);svg.setAttribute('height',layout.height);svg.setAttribute('preserveAspectRatio','xMidYMid meet');mzkRenderMazeBaseSafe(NS,svg,layout);const R=Math.round(layout.cellSize*0.39);(layout.fillerCells||[]).forEach((cell,i)=>{const g=mzkRenderFillerIcon(NS,MZK_THEME,i,layout.cellSize);g.setAttribute('transform','translate('+cell.x+','+cell.y+') scale(1.08)');svg.appendChild(g);});layout.nodes.forEach(node=>{const isEndpoint=node.kind==='start'||node.kind==='home';const vocab=isEndpoint?{image_url:'',word:''}:mzkNodeVocab(node);const g=document.createElementNS(NS,'g');g.setAttribute('class','mzk-node'+(node.kind==='branch'?' branch':'')+(node.kind==='start'?' start':'')+(node.kind==='home'?' end':''));g.dataset.nodeId=node.id;g.setAttribute('transform','translate('+node.x+','+node.y+')');const nodeR=node.kind==='home'?Math.round(R*1.5):R;const circle=document.createElementNS(NS,'circle');circle.setAttribute('class','mzk-node-circle');circle.setAttribute('r',nodeR);g.appendChild(circle);if(isEndpoint){const eIcon=mzkRenderEndpointIcon(NS,node.kind);eIcon.setAttribute('transform','scale('+(node.kind==='home'?1.52:1.2)+')');g.appendChild(eIcon);}else if(vocab.image_url){const inset=4;const img=document.createElementNS(NS,'image');img.setAttributeNS('http://www.w3.org/1999/xlink','href',vocab.image_url);img.setAttribute('href',vocab.image_url);img.setAttribute('x',-nodeR+inset);img.setAttribute('y',-nodeR+inset);img.setAttribute('width',(nodeR-inset)*2);img.setAttribute('height',(nodeR-inset)*2);img.setAttribute('clip-path','circle('+(nodeR-inset)+'px)');img.setAttribute('preserveAspectRatio','xMidYMid slice');g.appendChild(img);}if(!isEndpoint)g.addEventListener('click',()=>{if(typeof window.mzkNodeTap==='function'&&window.mzkNodeTap(node))return;mzkHandleTap(node,g);});svg.appendChild(g);});const wrap=document.getElementById('mzkMazeWrap');wrap.innerHTML='';wrap.appendChild(svg);}
function mzkHandleTap(node,groupEl){if(mzkDone)return;if(node.kind==='path'&&node.index===mzkNextIndex){groupEl.classList.add('done');mzkPlay(document.getElementById('mzkWinAudio'));mzkSetFeedback('Great job!','good');mzkSpeakWord(node.vocabularyId);mzkScores.push(1);mzkNextIndex++;mzkUpdateProgress();if(mzkNextIndex>=MZK_PATH.length)setTimeout(mzkFinish,500);return;}groupEl.classList.add('wrong');mzkPlay(document.getElementById(node.kind==='branch'?'mzkWrongAudio':'mzkLoseAudio'));mzkSetFeedback(node.kind==='branch'?'Dead end! Restart and try another path.':'Not yet. Follow the path.','bad');groupEl.classList.add('shake');}
function mzkSpeakWord(vocabularyId){const vocab=MZK_BANK_BY_ID[vocabularyId]||{},word=(vocab.word||'').toLowerCase();if(!word)return;if(window.speechSynthesis){window.speechSynthesis.cancel();const u=new SpeechSynthesisUtterance(word);u.rate=0.8;u.pitch=1.05;u.lang='en-US';window.speechSynthesis.speak(u);}}
function mzkFinish(){if(mzkDone)return;mzkDone=true;mzkRounds++;mzkNextIndex=MZK_PATH.length;mzkScores=Array(MZK_PATH.length).fill(1);mzkUpdateProgress();mzkPlay(document.getElementById('mzkDoneAudio'));mzkSetFeedback('Completed!','good');mzkShowUnscoredCompleted();}
function mzkShowUnscoredCompleted(){const stage=document.getElementById('mzkStage');const completedEl=document.getElementById('mzkCompleted');const n=MZK_PATH.length;stage.classList.add('is-completed');completedEl.classList.add('active');completedEl.innerHTML='<div class="af-unscored__card"><p class="af-unscored__prog-label">Path Completed</p><div class="af-unscored__prog-track"><div class="af-unscored__prog-fill" id="mzk-prog-fill" style="width:0%"></div></div><div class="af-unscored__prog-nums"><span>0</span><strong id="mzk-prog-text">0 / 0</strong></div><div class="af-unscored__icon"><svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="#7F77DD" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round"><path d="M20 6L9 17l-5-5"/></svg></div><p class="af-unscored__title">Maze complete!</p><p class="af-unscored__sub">Great job! You found the way home.</p><div class="af-unscored__chips af-unscored__chips--2"><div class="af-unscored__chip"><div class="af-unscored__chip-val af-unscored__chip-val--orange" id="mzk-stat1">0</div><div class="af-unscored__chip-lbl">Steps Completed</div></div><div class="af-unscored__chip"><div class="af-unscored__chip-val" id="mzk-stat2">0</div><div class="af-unscored__chip-lbl">Rounds</div></div></div><div class="af-unscored__banner af-unscored__banner--orange"><div class="af-unscored__banner-icon af-unscored__banner-icon--orange"><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#fff" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><path d="M13 2L3 14h9l-1 8 10-12h-9l1-8z"/></svg></div><div class="af-unscored__banner-text af-unscored__banner-text--orange"><span class="af-unscored__banner-title">Keep up the great work!</span>Try the maze again or continue to the next activity.</div></div><div class="af-unscored__btns"><button class="af-unscored__btn-secondary" id="mzkRestartCompleted">↺ Play Again</button><button class="af-unscored__btn-primary" id="mzkNextCompleted">Next →</button></div></div>';document.getElementById('mzk-prog-fill').style.width='100%';document.getElementById('mzk-prog-text').textContent=n+' / '+n;document.getElementById('mzk-stat1').textContent=String(n);document.getElementById('mzk-stat2').textContent=String(mzkRounds);document.getElementById('mzkRestartCompleted').addEventListener('click',mzkRestart);document.getElementById('mzkNextCompleted').addEventListener('click',mzkGoNext);if(MZK_RETURN_TO&&MZK_ACTIVITY_ID){const sep=MZK_RETURN_TO.indexOf('?')!==-1?'&':'?';fetch(MZK_RETURN_TO+sep+'activity_percent=100&activity_errors=0&activity_total='+n+'&activity_id='+encodeURIComponent(MZK_ACTIVITY_ID)+'&activity_type=maze_kids',{method:'GET',credentials:'same-origin',cache:'no-store'}).catch(function(){});}}
function mzkResetViewerState(){mzkNextIndex=0;mzkDone=false;mzkScores=[];document.getElementById('mzkStage').classList.remove('is-completed');document.getElementById('mzkCompleted').classList.remove('active');document.getElementById('mzkCompleted').innerHTML='';mzkSetFeedback('','');mzkUpdateProgress();}
function mzkRestart(){mzkResetViewerState();mzkBuildMaze();}
function mzkShowAnswers(){const svg=document.querySelector('#mzkMazeWrap svg');if(!svg)return;mzkClearAnswerPath();const layout=mzkLastLayout||generateMazeLayout(MZK_PATH,MZK_BRANCHES,MZK_LAYOUT_POSITIONS);const ordered=[];const start=layout.nodes.find(n=>n.kind==='start');const home=layout.nodes.find(n=>n.kind==='home');if(start)ordered.push(start);layout.nodes.filter(n=>n.kind==='path').sort((a,b)=>a.index-b.index).forEach(n=>ordered.push(n));if(home)ordered.push(home);if(ordered.length<2)return;const NS='http://www.w3.org/2000/svg';const d=ordered.map((n,i)=>(i?'L ':'M ')+n.x+' '+n.y).join(' ');const path=document.createElementNS(NS,'path');path.setAttribute('class','mzk-answer-path');path.setAttribute('d',d);svg.appendChild(path);ordered.forEach(n=>{const dot=document.createElementNS(NS,'circle');dot.setAttribute('class','mzk-answer-dot');dot.setAttribute('cx',n.x);dot.setAttribute('cy',n.y);dot.setAttribute('r',n.kind==='start'||n.kind==='home'?12:8);svg.appendChild(dot);});mzkSetFeedback('Answer path shown. Follow the orange line from START to HOME.','good');}
function mzkGoNext(){const candidates=Array.from(document.querySelectorAll('a,button')).filter(el=>!['mzkNextBtn','mzkNextCompleted'].includes(el.id));const target=candidates.find(el=>/next|finish unit|continue/i.test((el.textContent||'').trim())&&el.offsetParent!==null);if(target){target.click();return;}if(MZK_RETURN_TO){window.location.href=MZK_RETURN_TO;return;}window.history.back();}
mzkBuildMaze();mzkUpdateProgress();
</script><?php
